macroActions.command:
ifShift {
    holdKey 1
    exit
}

ifPlaytime 200 {
    tapKey f1
    exit
}

ifInterrupted {
    tapKey f1
    exit
}

holdKey 1

if ($lastOperator == 1) {
    setVar count $lastCount

    // WORD (1)
    if ($lastMotion == 1) {
        while ($count > 0) {
            tapKeySeq LSA-right LS-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // BACK_WORD (2)
    if ($lastMotion == 2) {
        while ($count > 0) {
            tapKeySeq LSA-left
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // END_WORD (3)
    if ($lastMotion == 3) {
        while ($count > 0) {
            tapKeySeq LSA-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // LINE (4)
    if ($lastMotion == 4) {
        while ($count > 0) {
            tapKey LG-left
            tapKeySeq LSG-right
            tapKey backspace
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // TO_EOL (5)
    if ($lastMotion == 5) {
        while ($count > 0) {
            tapKeySeq LSG-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // DOWN (6)
    if ($lastMotion == 6) {
        while ($count > 0) {
            tapKey LG-left
            tapKeySeq LSG-right LS-down
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // UP (7)
    if ($lastMotion == 7) {
        while ($count > 0) {
            tapKey up
            tapKey LG-left
            tapKeySeq LSG-right LS-down
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // LEFT (8)
    if ($lastMotion == 8) {
        while ($count > 0) {
            tapKeySeq LS-left
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // RIGHT (9)
    if ($lastMotion == 9) {
        while ($count > 0) {
            tapKeySeq LS-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
}

ifShift suppressMods {
    tapKey LG-right
}
else suppressMods {
    tapKey right
}

switchKeymap MIK

// VISUAL LINE mode: back motion is no-op
if ($mode == 3) final setVar count 0
// VISUAL mode: shift+motion to extend selection
if ($mode == 2) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKey LSA-left
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKey LSA-left
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 2
    setVar lastCount $count
    while ($count > 0)
    {
        tapKeySeq LSA-left
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKey LA-left
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKey LA-left

ifGesture w final {
    tapKeySeq LSA-right
    tapKey backspace
    switchKeymap MIK
}

// give the modifier state one scan to settle
noOp

// Visual mode: delete selection
if ($mode == 2 || $mode == 3)
{
    tapKey backspace
    setVar mode 0
    setVar count 0
    set backlight.constantRgb.rgb 255 192 32
}
else
{
    // Shift held means Vim "X", delete left
    ifShift final holdKey backspace
    // otherwise Vim "x", delete right
    holdKey delete
}

noOp

// Visual mode: delete selection
if ($mode == 2 || $mode == 3)
{
    tapKey backspace
    setVar mode 0
    setVar operator 0
    setVar count 0
    set backlight.constantRgb.rgb 255 192 32
}
else
{
    // Shift+d = D (delete to end of line)
    ifShift final
    {
        suppressMods
        {
            if ($count == 0)
            {
                setVar count 1
            }
            setVar lastOperator 1
            setVar lastMotion 5
            setVar lastCount $count
            while ($count > 0)
            {
                tapKeySeq LSG-right
                tapKey backspace
                setVar count ($count - 1)
            }
            setVar operator 0
            setVar count 0
        }
    }
    // dd = delete whole line (operator already pending)
    if ($operator == 1)
    {
        if ($count == 0)
        {
            setVar count 1
        }
        setVar lastOperator 1
        setVar lastMotion 4
        setVar lastCount $count
        while ($count > 0)
        {
            tapKey LG-left
            tapKeySeq LSG-right
            tapKey backspace
            tapKey backspace
            setVar count ($count - 1)
        }
        setVar operator 0
        setVar count 0
    }
    else
    {
        // First press: enter delete operator mode
        setVar operator 1
    }
}

// VISUAL modes: extend selection down
if ($mode == 2 || $mode == 3) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKey LS-down
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKey LS-down
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 6
    setVar lastCount $count
    while ($count > 0)
    {
        tapKey LG-left
        tapKeySeq LSG-right LS-down
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKey down
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKey down

// VISUAL LINE mode: end motion is no-op
if ($mode == 3) final setVar count 0
// VISUAL mode: shift+motion to extend selection
if ($mode == 2) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKey LSA-right
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKey LSA-right
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 3
    setVar lastCount $count
    while ($count > 0)
    {
        tapKeySeq LSA-right
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKey LA-right
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKey LA-right

// exit visual modes: deselect and return to normal
if ($mode == 2 || $mode == 3)
{
    tapKey right
    setVar mode 0
    setVar operator 0
    setVar count 0
    set backlight.constantRgb.rgb 255 192 32
}
else
{
    setVar operator 0
    setVar count 0
    setVar mode 0
    tapKey escape
}

ifShift suppressMods {
    tapKey LG-left
}
switchKeymap MIK

// VISUAL LINE mode: left motion is no-op
if ($mode == 3) final setVar count 0
// VISUAL mode: extend selection left
if ($mode == 2) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKey LS-left
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKey LS-left
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 8
    setVar lastCount $count
    while ($count > 0)
    {
        tapKeySeq LS-left
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKey left
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKey left

ifShift suppressMods {
    tapKey LG-left
    tapKey enter
    tapKey up
    switchKeymap MIK
}
else {
    suppressMods {
        tapKey LG-right
        tapKey enter
    }
    switchKeymap MIK
}

noOp

// Visual mode: paste over selection
if ($mode == 2 || $mode == 3)
{
    suppressMods
    {
        tapKey LG-v
    }
    setVar mode 0
    setVar count 0
    set backlight.constantRgb.rgb 255 192 32
}
else
{
    ifShift final suppressMods
    {
        tapKey LG-v
    }
    suppressMods
    {
        tapKey right
        tapKey LG-v
    }
}

// VISUAL LINE mode: right motion is no-op
if ($mode == 3) final setVar count 0
// VISUAL mode: extend selection right
if ($mode == 2) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKey LS-right
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKey LS-right
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 9
    setVar lastCount $count
    while ($count > 0)
    {
        tapKeySeq LS-right
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKey right
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKey right

// VISUAL modes: extend selection up
if ($mode == 2 || $mode == 3) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKey LS-up
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKey LS-up
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 7
    setVar lastCount $count
    while ($count > 0)
    {
        tapKey up
        tapKey LG-left
        tapKeySeq LSG-right LS-down
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKey up
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKey up

noOp

// Shift+V = visual-line mode
ifShift final
{
    if ($mode == 3)
    {
        // exit V-LINE: deselect, return to normal
        suppressMods
        {
            tapKey right
        }
        setVar mode 0
        setVar operator 0
        setVar count 0
        set backlight.constantRgb.rgb 255 192 32
    }
    else if ($mode == 2)
    {
        // switch from character visual to V-LINE
        setVar mode 3
        set backlight.constantRgb.rgb 255 0 0
    }
    else
    {
        // enter V-LINE from normal: select current line
        suppressMods
        {
            tapKey LG-left
            tapKeySeq LSG-right
        }
        setVar mode 3
        setVar operator 0
        setVar count 0
        set backlight.constantRgb.rgb 255 0 0
    }
}

// v = character visual mode
if ($mode == 2)
{
    // exit visual: deselect, return to normal
    tapKey right
    setVar mode 0
    setVar operator 0
    setVar count 0
    set backlight.constantRgb.rgb 255 192 32
}
else if ($mode == 3)
{
    // switch from V-LINE to character visual
    setVar mode 2
    set backlight.constantRgb.rgb 255 128 0
}
else
{
    // enter visual mode from normal
    setVar mode 2
    setVar operator 0
    setVar count 0
    set backlight.constantRgb.rgb 255 128 0
}

// VISUAL LINE mode: word motion is no-op in V-LINE
if ($mode == 3) final setVar count 0
// VISUAL mode: shift+motion to extend selection
if ($mode == 2) final
{
    if ($count > 0)
    {
        while ($count > 0)
        {
            tapKeySeq LSA-right LS-right
            setVar count ($count - 1)
        }
        setVar count 0
    }
    else
    {
        autoRepeat tapKeySeq LSA-right LS-right
    }
}
// DELETE operator
if ($operator == 1) final
{
    if ($count == 0)
    {
        setVar count 1
    }
    setVar lastOperator 1
    setVar lastMotion 1
    setVar lastCount $count
    while ($count > 0)
    {
        tapKeySeq LSA-right LS-right
        tapKey backspace
        setVar count ($count - 1)
    }
    setVar operator 0
    setVar count 0
}
// NORMAL motion
if ($count > 0) final
{
    while ($count > 0)
    {
        tapKeySeq LA-right right
        setVar count ($count - 1)
    }
    setVar count 0
}
autoRepeat tapKeySeq LA-right right

noOp

// Visual mode: yank selection, deselect
if ($mode == 2 || $mode == 3)
{
    suppressMods
    {
        tapKey LG-c
    }
    tapKey right
    setVar mode 0
    setVar count 0
    set backlight.constantRgb.rgb 255 192 32
}
else
{
    // Shift + y  → copy from cursor to end of line, then restore cursor
    ifShift final
    {
        suppressMods
        {
            tapKeySeq LSG-right
            tapKey LG-c
            tapKey left
        }
    }
    // yy → copy full line
    ifGesture y final
    {
        suppressMods
        {
            tapKey LG-left
            tapKeySeq LSG-right
            tapKey LG-c
            tapKey LG-right
        }
    }
    holdKey y
}

set autoRepeatDelay 120
set autoRepeatRate 30
set secondaryRole.defaultStrategy advanced
set secondaryRole.advanced.timeout 200
set secondaryRole.advanced.timeoutAction secondary
set secondaryRole.advanced.safetyMargin 0
set secondaryRole.advanced.triggerByRelease 0
set secondaryRole.advanced.doubletapToPrimary 1
set secondaryRole.advanced.doubletapTime 200

// mode meanings:
// 0 = NORMAL   (default; motions/operators/commands)
// 1 = INSERT   (keys pass through as typing; Esc returns to NORMAL)
// 2 = VISUAL   (character selection; motions extend selection with Shift)
// 3 = VISUAL LINE (full-line selection; j/k extend by line)
// 4 = REPLACE  (optional later; like Vim R)
// 5 = COMMAND  (optional later; ":" / ex-like command entry)
setVar mode 0
// operator meanings:
// 0 = NONE
// 1 = DELETE
setVar operator 0
// tracks the number of times to do a change (supports multi-digit like 23dw)
setVar count 0

// last executed change, used for the . key
setVar lastOperator 0
// motion meanings:
// 0 = NONE
// 1 = WORD (w)
// 2 = BACK_WORD (b)
// 3 = END_WORD (e)
// 4 = LINE (dd)
// 5 = TO_EOL (D)
// 6 = DOWN (j)
// 7 = UP (k)
// 8 = LEFT (h)
// 9 = RIGHT (l)
setVar lastMotion 0
setVar lastCount 0

ifLayer fn2 {
    untoggleLayer
    set backlight.constantRgb.rgb 255 192 32
    tapKey escape
}
else {
    toggleLayer fn2
    set backlight.constantRgb.rgb 255 0 0
}
